def now_iso():
    return now_local().isoformat(timespec="seconds")


def now_local():
    return datetime.now(timezone(timedelta(hours=TIMEZONE_OFFSET_HOURS)))


def _sql_lit(value):
    return "'" + str(value).replace("'", "''") + "'"

def _sql_utf8(value):
    return _sql_lit("" if value is None else str(value))


def _sql_opt_utf8(value):
    if value is None:
        return "NULL"
    return _sql_lit(str(value))


def _sql_int(value):
    return str(int(value))


def _sql_opt_int(value):
    if value is None:
        return "NULL"
    return str(int(value))


def _sql_bool(value):
    return "true" if bool(value) else "false"


def _tv_utf8(value):
    return ydb.TypedValue("" if value is None else str(value), ydb.PrimitiveType.Utf8)


def _tv_int64(value):
    return ydb.TypedValue(int(value), ydb.PrimitiveType.Int64)


def _tv_int32(value):
    return ydb.TypedValue(int(value), ydb.PrimitiveType.Int32)


def _tv_bool(value):
    return ydb.TypedValue(bool(value), ydb.PrimitiveType.Bool)


def _tv_opt_int64(value):
    if value is None:
        return ydb.TypedValue(None, ydb.OptionalType(ydb.PrimitiveType.Int64))
    return ydb.TypedValue(int(value), ydb.OptionalType(ydb.PrimitiveType.Int64))


def _tv_opt_utf8(value):
    if value is None:
        return ydb.TypedValue(None, ydb.OptionalType(ydb.PrimitiveType.Utf8))
    return ydb.TypedValue(str(value), ydb.OptionalType(ydb.PrimitiveType.Utf8))


def _query_tag(query):
    q = " ".join((query or "").strip().split())
    return q[:180]


def _normalize_endpoint(endpoint):
    endpoint = (endpoint or "").strip()
    if endpoint and "://" not in endpoint:
        # YDB python SDK works reliably with explicit scheme.
        return f"grpcs://{endpoint}"
    return endpoint


def _get_driver():
    global _driver
    if _driver is not None:
        LOGGER.debug("YDB driver cache hit")
        return _driver

    endpoint = _normalize_endpoint(YDB_ENDPOINT or os.getenv("YDB_ENDPOINT"))
    database = (DB_PATH or os.getenv("YDB_DATABASE") or "").strip()
    if not endpoint or not database:
        raise RuntimeError("YDB_ENDPOINT or YDB_DATABASE not set")
    LOGGER.info("YDB init endpoint=%s database=%s", endpoint, database)

    token = (YDB_TOKEN or os.getenv("YDB_TOKEN") or "").strip()
    if token and token not in {"None", "null", "-"}:
        try:
            LOGGER.info("YDB auth mode=token")
            driver = ydb.Driver(
                endpoint=endpoint,
                database=database,
                credentials=ydb.AuthTokenCredentials(token),
            )
            driver.wait(fail_fast=True, timeout=4)
            _driver = driver
            return driver
        except Exception:
            LOGGER.exception("YDB token auth failed, falling back to metadata credentials")

    # Cloud Function service account credentials.
    LOGGER.info("YDB auth mode=metadata")
    driver = ydb.Driver(
        endpoint=endpoint,
        database=database,
        credentials=ydb.iam.MetadataUrlCredentials(),
    )
    driver.wait(fail_fast=True, timeout=4)
    _driver = driver
    return driver


def _get_pool():
    global _pool
    if _pool is not None:
        return _pool
    driver = _get_driver()
    _pool = ydb.SessionPool(driver)
    return _pool


def _session():
    driver = _get_driver()
    return driver.table_client.session().create()


def _exec(query, params=None):
    LOGGER.debug("YDB EXEC query=%s params_keys=%s", _query_tag(query), sorted((params or {}).keys()))
    try:
        pool = _get_pool()
        result = pool.retry_operation_sync(
            lambda session: session.transaction().execute(query, params or {}, commit_tx=True)
        )
        LOGGER.debug("YDB EXEC OK query=%s", _query_tag(query))
        return result
    except Exception:
        LOGGER.exception("YDB EXEC FAILED via pool query=%s", _query_tag(query))
        # Fallback to direct session for resilience
        session = _session()
        try:
            result = session.transaction().execute(query, params or {}, commit_tx=True)
            LOGGER.debug("YDB EXEC OK (fallback) query=%s", _query_tag(query))
            return result
        finally:
            try:
                session.close()
            except Exception:
                pass


def _schema(query):
    # YDB may temporarily reject frequent schema ops with rate limits.
    last_exc = None
    for attempt in range(4):
        LOGGER.info("YDB SCHEMA attempt=%s query=%s", attempt + 1, _query_tag(query))
        session = _session()
        try:
            session.execute_scheme(query)
            LOGGER.info("YDB SCHEMA OK query=%s", _query_tag(query))
            return
        except Exception as exc:
            last_exc = exc
            msg = str(exc).lower()
            if "schema operations" not in msg and "try again later" not in msg:
                raise
            LOGGER.warning("YDB SCHEMA RETRY attempt=%s error=%s", attempt + 1, str(exc)[:200])
            # Keep webhook latency bounded: 0.1, 0.2, 0.4, 0.8s
            time.sleep(0.1 * (2 ** attempt))
        finally:
            try:
                session.close()
            except Exception:
                pass
    raise last_exc


def _schema_optional(query, ignore_substrings=None):
    try:
        _schema(query)
    except Exception as exc:
        msg = str(exc).lower()
        if ignore_substrings and any(token in msg for token in ignore_substrings):
            LOGGER.info("YDB SCHEMA optional skipped query=%s error=%s", _query_tag(query), str(exc)[:200])
            return
        raise


def _id_from_time():
    return int(time.time() * 1000) * 1000 + random.randint(0, 999)


