def log_action(action, actor_id=None, target_type=None, target_id=None, meta=None):
    created_at = now_iso()
    log_id = _id_from_time()
    query = (
        "UPSERT INTO logs (log_id, action, actor_id, target_type, target_id, meta, created_at) "
        f"VALUES ({_sql_int(log_id)}, {_sql_utf8(action)}, {_sql_opt_int(actor_id)}, "
        f"{_sql_utf8(target_type or '')}, {_sql_opt_int(target_id)}, {_sql_opt_utf8(meta)}, "
        f"{_sql_lit(created_at)});"
    )
    _exec(query)


def get_user(user_id):
    _ensure_users_schema_once()
    query = f"SELECT * FROM users WHERE user_id = {_sql_int(user_id)};"
    res = _exec(query)
    rows = res[0].rows
    return rows[0] if rows else None


def get_user_by_username(username):
    _ensure_users_schema_once()
    query = f"SELECT * FROM users WHERE username = {_sql_utf8(username)};"
    res = _exec(query)
    rows = res[0].rows
    return rows[0] if rows else None


def upsert_user(user_id, first_name, username, role=None, client_status=None):
    _ensure_users_schema_once()
    now = now_iso()
    existing = get_user(user_id)
    created_at = existing.get("created_at") if existing else now
    resolved_role = role or ROLE_CLIENT
    if resolved_role == ROLE_CLIENT:
        if client_status is None:
            client_status = (existing or {}).get("client_status") or CLIENT_STATUS_NEW
    else:
        client_status = None
    query = (
        "UPSERT INTO users (user_id, first_name, username, role, client_status, is_active, created_at, updated_at) "
        f"VALUES ({_sql_int(user_id)}, {_sql_utf8(first_name or '')}, {_sql_utf8(username or '')}, "
        f"{_sql_utf8(resolved_role)}, {_sql_opt_utf8(client_status)}, {_sql_bool(True)}, "
        f"{_sql_lit(created_at)}, {_sql_lit(now)});"
    )
    _exec(query)
