def next_day_seq():
    today = now_local().date().isoformat()
    query = (
        "SELECT COUNT(*) AS cnt FROM projects "
        f"WHERE Substring(CAST(created_at AS String), 0, 10) = {_sql_utf8(today)};"
    )
    res = _exec(query)
    cnt = res[0].rows[0]["cnt"] if res[0].rows else 0
    return int(cnt) + 1


def create_project(group_id, group_title, created_by, day_seq):
    _ensure_projects_schema_once()
    existing = get_project_by_group(group_id)
    if existing:
        # Idempotency guard for duplicated commands/events in the same group.
        return existing["project_id"], (existing.get("proj_code") or "")
    project_id = _id_from_time()
    proj_code = f"PRJ-{now_local().strftime('%Y%m%d')}-{day_seq}"
    now = now_iso()
    query = (
        "UPSERT INTO projects "
        "(project_id, proj_code, status, is_active, group_id, group_title, created_by, day_seq, created_at, updated_at) "
        f"VALUES ({_sql_int(project_id)}, {_sql_utf8(proj_code)}, {_sql_utf8('')}, {_sql_bool(True)}, "
        f"{_sql_int(group_id)}, {_sql_utf8(group_title or '')}, {_sql_int(created_by)}, {_sql_int(day_seq)}, "
        f"{_sql_lit(now)}, {_sql_lit(now)});"
    )
    _exec(query)
    try:
        ensure_default_stage(project_id)
    except Exception:
        LOGGER.exception("Failed to create default stage for project_id=%s", project_id)
    return project_id, proj_code


