def set_project_client(project_id, client_id, changed_by=None):
    _ensure_projects_schema_once()
    _ensure_project_clients_schema_once()
    updated_at = now_iso()
    project_id = int(project_id)
    client_id = int(client_id) if client_id is not None else None
    if client_id is None:
        _exec(
            "UPDATE project_clients SET is_active = false "
            f"WHERE project_id = {_sql_int(project_id)} AND is_active = true;"
        )
        _exec(
            "UPDATE projects SET "
            f"active_client_id = NULL, client_id = NULL, updated_at = {_sql_lit(updated_at)} "
            f"WHERE project_id = {_sql_int(project_id)};"
        )
        return

    _exec(
        "UPDATE project_clients SET is_active = false "
        f"WHERE project_id = {_sql_int(project_id)} AND is_active = true;"
    )
    _exec(
        "UPSERT INTO project_clients (project_id, client_id, is_active, changed_at, changed_by) "
        f"VALUES ({_sql_int(project_id)}, {_sql_int(client_id)}, {_sql_bool(True)}, "
        f"{_sql_lit(updated_at)}, {_sql_opt_int(changed_by)});"
    )
    _exec(
        "UPDATE projects SET "
        f"active_client_id = {_sql_opt_int(client_id)}, client_id = {_sql_opt_int(client_id)}, "
        f"updated_at = {_sql_lit(updated_at)} "
        f"WHERE project_id = {_sql_int(project_id)};"
    )


