def create_deal(project_id, client_id, title, created_by, status=DEAL_STATUS_KP_SENT, developer_id=None):
    _ensure_deals_schema_once()
    project_id = int(project_id) if project_id else 0
    if project_id and client_id:
        existing = get_deal_for_project_client(project_id, client_id)
        if existing and existing.get("deal_id"):
            LOGGER.info(
                "Skip duplicate deal create for project_id=%s client_id=%s existing_deal_id=%s",
                project_id,
                client_id,
                existing.get("deal_id"),
            )
            return existing["deal_id"]
    deal_id = _id_from_time()
    now = now_iso()
    query = (
        "UPSERT INTO deals "
        "(deal_id, project_id, client_id, title, deal_status, developer_id, is_active, created_by, created_at, updated_at) "
        f"VALUES ({_sql_int(deal_id)}, {_sql_int(project_id)}, {_sql_int(client_id)}, "
        f"{_sql_utf8(title or '')}, {_sql_utf8(status)}, {_sql_opt_int(developer_id)}, {_sql_bool(True)}, "
        f"{_sql_int(created_by)}, {_sql_lit(now)}, {_sql_lit(now)});"
    )
    _exec(query)
    add_deal_status_history(deal_id, None, status, created_by, note=None)
    if project_id:
        try:
            set_project_client(project_id, client_id, changed_by=created_by)
        except Exception:
            LOGGER.exception("Failed to set active client for project_id=%s", project_id)
    return deal_id


