def update_deal_status(deal_id, new_status, changed_by, note=None, allow_same=False):
    _ensure_deals_schema_once()
    deal = get_deal(deal_id)
    if not deal:
        return False, "deal_not_found"
    current_status = deal.get("deal_status")
    if current_status == new_status and allow_same:
        return True, None
    allowed_next = DEAL_STATUS_TRANSITIONS.get(current_status, set())
    if current_status and new_status not in allowed_next and new_status != current_status:
        return False, "invalid_status_transition"
    updated_at = now_iso()
    query = (
        "UPDATE deals SET "
        f"deal_status = {_sql_utf8(new_status)}, updated_at = {_sql_lit(updated_at)} "
        f"WHERE deal_id = {_sql_int(deal_id)};"
    )
    _exec(query)
    add_deal_status_history(deal_id, current_status, new_status, changed_by, note=note)
    return True, None


