def delete_deal(deal_id, deleted_by=None):
    _ensure_deals_schema_once()
    deal = get_deal(deal_id)
    if not deal or not deal.get("is_active"):
        return False, "deal_not_active"

    pay_res = _exec(
        "SELECT COUNT(*) AS cnt FROM payments "
        f"WHERE deal_id = {_sql_int(deal_id)};"
    )
    pay_cnt = pay_res[0].rows[0]["cnt"] if pay_res and pay_res[0].rows else 0
    if int(pay_cnt) > 0:
        return False, "deal_has_payments"

    updated_at = now_iso()
    _exec(
        "UPDATE deals SET "
        f"is_active = false, updated_at = {_sql_lit(updated_at)} "
        f"WHERE deal_id = {_sql_int(deal_id)};"
    )

    project_id = deal.get("project_id")
    if project_id:
        replacement_deal = _latest_active_deal_for_project(project_id)
        replacement_client_id = replacement_deal.get("client_id") if replacement_deal else None
        try:
            set_project_client(project_id, replacement_client_id, changed_by=deleted_by)
        except Exception:
            LOGGER.exception("Failed to rebind project client after deal delete project_id=%s", project_id)

    return True, None


