def create_manual_client(display_name, username=None, client_status=None):
    _ensure_users_schema_once()
    display_name = (display_name or "").strip()
    if display_name.startswith("@"):  # normalize username
        username = display_name[1:]
        display_name = display_name[1:] or "Клиент"

    query_min = """SELECT MIN(user_id) AS min_id FROM users;"""
    res = _exec(query_min)
    min_id = res[0].rows[0]["min_id"] if res[0].rows else 0
    min_id = min_id if min_id is not None else 0
    new_id = int(min_id) - 1 if int(min_id) <= 0 else -1

    now = now_iso()
    if client_status is None:
        client_status = CLIENT_STATUS_NEW
    query = (
        "UPSERT INTO users (user_id, first_name, username, role, client_status, is_active, created_at, updated_at) "
        f"VALUES ({_sql_int(new_id)}, {_sql_utf8(display_name)}, {_sql_utf8(username or '')}, "
        f"{_sql_utf8(ROLE_CLIENT)}, {_sql_opt_utf8(client_status)}, {_sql_bool(True)}, "
        f"{_sql_lit(now)}, {_sql_lit(now)});"
    )
    _exec(query)
    add_client_status_history(new_id, None, client_status, 0, note="Создание клиента")
    return new_id


