def delete_client(user_id):
    _ensure_users_schema_once()
    deals_res = _exec(
        "SELECT deal_id, deal_status FROM deals "
        f"WHERE client_id = {_sql_int(user_id)} AND is_active = true;"
    )
    active_deals = deals_res[0].rows if deals_res and deals_res[0].rows else []
    if active_deals:
        # Allow deleting mistaken clients only when no payments
        # and all active deals are still in KP_SENT status.
        if any(d.get("deal_status") != DEAL_STATUS_KP_SENT for d in active_deals):
            return False, "client_has_deals"
        deal_ids = [str(int(d["deal_id"])) for d in active_deals if d.get("deal_id") is not None]
        if deal_ids:
            pay_res = _exec(
                "SELECT COUNT(*) AS cnt FROM payments "
                "WHERE deal_id IN (" + ",".join(deal_ids) + ");"
            )
            pay_cnt = pay_res[0].rows[0]["cnt"] if pay_res[0].rows else 0
            if int(pay_cnt) > 0:
                return False, "client_has_deals"
            now = now_iso()
            _exec(
                "UPDATE deals SET is_active = false, updated_at = "
                f"{_sql_lit(now)} WHERE deal_id IN (" + ",".join(deal_ids) + ");"
            )

    # Clean up client bindings in projects/groups
    _exec(
        "UPDATE projects SET active_client_id = NULL, client_id = NULL "
        f"WHERE active_client_id = {_sql_int(user_id)} OR client_id = {_sql_int(user_id)};"
    )
    _exec(f"DELETE FROM project_clients WHERE client_id = {_sql_int(user_id)};")
    _exec(f"DELETE FROM project_members WHERE user_id = {_sql_int(user_id)};")
    _exec(f"DELETE FROM users WHERE user_id = {_sql_int(user_id)};")
    return True, None


def update_project_group_title(project_id, group_title):
    _ensure_projects_schema_once()
    updated_at = now_iso()
    query = (
        "UPDATE projects SET "
        f"group_title = {_sql_utf8(group_title or '')}, updated_at = {_sql_lit(updated_at)} "
        f"WHERE project_id = {_sql_int(project_id)};"
    )
    _exec(query)


def has_active_projects(user_id):
    query = (
        "SELECT 1 AS ok FROM deals "
        f"WHERE client_id = {_sql_int(user_id)} AND is_active = true LIMIT 1;"
    )
    res = _exec(query)
    return bool(res[0].rows)


def update_project_status(project_id, status):
    _ensure_projects_schema_once()
    updated_at = now_iso()
    query = (
        "UPDATE projects SET "
        f"status = {_sql_utf8(status)}, updated_at = {_sql_lit(updated_at)} "
        f"WHERE project_id = {_sql_int(project_id)};"
    )
    _exec(query)


def archive_project(project_id):
    _ensure_projects_schema_once()
    updated_at = now_iso()
    query = (
        "UPDATE projects SET is_active = false, updated_at = "
        f"{_sql_lit(updated_at)} WHERE project_id = {_sql_int(project_id)};"
    )
    _exec(query)


def create_invite(token, role, expires_at):
    query = (
        "UPSERT INTO invites (token, role, expires_at) "
        f"VALUES ({_sql_utf8(token)}, {_sql_utf8(role)}, {_sql_utf8(expires_at)});"
    )
    _exec(query)


def consume_invite(token, user_id):
    _ensure_users_schema_once()
    query = f"SELECT * FROM invites WHERE token = {_sql_utf8(token)} AND used_by IS NULL;"
    res = _exec(query)
    rows = res[0].rows
    if not rows:
        return None
    row = rows[0]
    if row.get("expires_at") and row["expires_at"] < now_iso():
        return None

    used_at = now_iso()
    upd = (
        "UPDATE invites SET "
        f"used_by = {_sql_int(user_id)}, used_at = {_sql_lit(used_at)} "
        f"WHERE token = {_sql_utf8(token)};"
    )
    _exec(upd)
    return row.get("role")


def list_invites(role=None, include_used=False):
    where = []
    if role:
        where.append(f"role = {_sql_utf8(role)}")
    if not include_used:
        where.append("used_by IS NULL")
    where_sql = (" WHERE " + " AND ".join(where)) if where else ""
    query = (
        "SELECT token, role, expires_at, used_by, used_at "
        f"FROM invites{where_sql} ORDER BY expires_at DESC;"
    )
    res = _exec(query)
    return res[0].rows


def delete_invite(token):
    _exec(f"DELETE FROM invites WHERE token = {_sql_utf8(token)};")


def list_active_invites(role=None):
    if role:
        query = (
            "SELECT token, role, expires_at, used_by, used_at "
            f"FROM invites WHERE role = {_sql_utf8(role)} AND used_by IS NULL "
            "ORDER BY expires_at DESC;"
        )
    else:
        query = "SELECT token, role, expires_at, used_by, used_at FROM invites WHERE used_by IS NULL ORDER BY expires_at DESC;"
    res = _exec(query)
    return res[0].rows


def list_developers():
    _ensure_users_schema_once()
    query = (
        "SELECT user_id, first_name, username, is_active, created_at, updated_at "
        f"FROM users WHERE role = {_sql_utf8(ROLE_DEVELOPER)} ORDER BY created_at DESC;"
    )
    res = _exec(query)
    return res[0].rows
