def parse_invite(args):
    if not args:
        return None
    token = args[0]
    if token.startswith("inv_"):
        return token[4:]
    return None


async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    logging.info("START from user=%s username=%s", update.effective_user.id, update.effective_user.username)
    user = update.effective_user
    first_name = user.first_name or "Пользователь"
    username = user.username

    role = ROLE_CLIENT
    if is_admin_user(user):
        role = ROLE_ADMIN

    existing = get_user(user.id)
    if existing and existing.get("role"):
        role = existing["role"]

    token = parse_invite(context.args)
    if token:
        invite_role = consume_invite(token, user.id)
        if invite_role:
            role = invite_role
            await update.message.reply_text("✅ Приглашение принято. Роль назначена.")
        else:
            await update.message.reply_text("❌ Ссылка недействительна или истекла.")

    upsert_user(user.id, first_name, username, role=role)
    has_projects = False
    if role == ROLE_CLIENT:
        has_projects = has_active_projects(user.id)
        if not existing:
            log_action("client_registered_by_start", user.id, "user", user.id, None)
            try:
                await context.bot.send_message(
                    chat_id=f"@{MANAGER_USERNAME}",
                    text=f"Новый клиент: {user.first_name or 'Клиент'} (@{user.username or 'нет'})",
                )
            except Exception:
                pass

    await update.message.reply_text(
        f"Привет, {first_name}! 👋\n"
        "Выбери, чем могу помочь:",
        reply_markup=main_menu(role, has_projects=has_projects),
    )


async def handle_forwarded(update: Update, context: ContextTypes.DEFAULT_TYPE):
    logging.info("FORWARDED from user=%s username=%s", update.effective_user.id, update.effective_user.username)
    message = update.message
    actor = update.effective_user

    if not is_admin_user(actor):
        await message.reply_text("❌ Только администратор может регистрировать клиентов.")
        return

    sender = None
    if hasattr(message, "forward_origin") and message.forward_origin:
        forward_origin = message.forward_origin
        if isinstance(forward_origin, TelegramUser):
            sender = forward_origin
        elif hasattr(forward_origin, "sender_user") and forward_origin.sender_user:
            sender = forward_origin.sender_user
    elif getattr(message, "forward_from", None):
        sender = message.forward_from

    if not sender:
        await message.reply_text(
            "❌ Не могу получить отправителя.\n"
            "Причина: Telegram скрывает автора при пересылке.\n"
            "Решение: попросите клиента разрешить пересылку без анонимизации."
        )
        return

    user_id = sender.id
    first_name = sender.first_name or "Клиент"
    username = sender.username

    existed = get_user(user_id) is not None
    upsert_user(user_id, first_name, username, role=ROLE_CLIENT)
    log_action("client_registered_by_forward", actor.id, "user", user_id, None)

    if existed:
        text = (
            "ℹ️ Клиент уже зарегистрирован.\n"
            f"🔹 Имя: {first_name}\n"
            f"🔹 ID: `{user_id}`\n"
            f"🔹 Username: @{username or 'не указан'}"
        )
    else:
        text = (
            "✅ Пользователь зарегистрирован!\n"
            f"🔹 Имя: {first_name}\n"
            f"🔹 ID: `{user_id}`\n"
            f"🔹 Username: @{username or 'не указан'}"
        )

    await message.reply_text(text)


async def handle_private_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    message = update.message
    user = update.effective_user

    if update.effective_chat.type != "private":
        return

    existing = get_user(user.id)
    if is_admin_user(user):
        upsert_user(user.id, user.first_name or "Админ", user.username, role=ROLE_ADMIN)
