    if not existing:
        upsert_user(user.id, user.first_name or "Клиент", user.username, role=ROLE_CLIENT)
        log_action("client_registered_by_message", user.id, "user", user.id, None)
        try:
            await context.bot.send_message(
                chat_id=f"@{MANAGER_USERNAME}",
                text=f"Новый клиент: {user.first_name or 'Клиент'} (@{user.username or 'нет'})",
            )
        except Exception:
            pass
        await message.reply_text(
            "✅ Вы зарегистрированы. Для начала воспользуйтесь меню /start."
        )


