async def on_chat_member(update: Update, context: ContextTypes.DEFAULT_TYPE):
    logging.info("CHAT_MEMBER update in chat=%s", update.effective_chat.id)
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        return

    project = get_project_by_group(chat.id)
    if not project:
        return

    member = update.chat_member
    if member.new_chat_member.status not in (
        ChatMemberStatus.MEMBER,
        ChatMemberStatus.ADMINISTRATOR,
        ChatMemberStatus.OWNER,
    ):
        return

    new_user = member.new_chat_member.user
    await process_user_join(chat, project, new_user, context)


async def process_user_join(chat, project, new_user, context):
    if new_user.is_bot:
        return
    join_key = f"{chat.id}:{new_user.id}"
    now_ts = time.time()
    with _join_guard_lock:
        prev_ts = _recent_join_events.get(join_key)
        if prev_ts and (now_ts - prev_ts) < 20:
            LOGGER.info("Skip duplicate join event key=%s", join_key)
            return
        _recent_join_events[join_key] = now_ts
        # Keep cache bounded and forget old keys.
        stale_keys = [k for k, ts in _recent_join_events.items() if (now_ts - ts) > 120]
        for key in stale_keys:
            _recent_join_events.pop(key, None)

    existing_user = get_user(new_user.id)
    role = ROLE_CLIENT
    if existing_user and existing_user["role"]:
        role = existing_user["role"]

    if role in (ROLE_ADMIN, ROLE_OWNER):
        add_project_member(project["project_id"], new_user.id, ROLE_ADMIN)
        return

    if role == ROLE_DEVELOPER:
        add_project_member(project["project_id"], new_user.id, ROLE_DEVELOPER)
        log_action("developer_joined_project", new_user.id, "project", project["project_id"], None)
        return

    # Клиент по умолчанию
    upsert_user(new_user.id, new_user.first_name or "Клиент", new_user.username, role=ROLE_CLIENT)
    existing_deal = get_deal_for_project_client(project["project_id"], new_user.id)
    if not existing_deal:
        create_deal(
            project_id=project["project_id"],
            client_id=new_user.id,
            title="Новая сделка",
            created_by=new_user.id,
            status=DEAL_STATUS_KP_SENT,
        )
        log_action("deal_created_auto", new_user.id, "project", project["project_id"], None)
    try:
        set_project_client(project["project_id"], new_user.id, changed_by=new_user.id)
    except Exception:
        LOGGER.exception("Failed to set active client for project_id=%s", project["project_id"])

    date_part = now_local().strftime("%d%m")
    client_label = f"@{new_user.username}" if new_user.username else (new_user.first_name or "client")
    new_title = f"AC_{date_part}L{project['day_seq']}_{client_label}"
    try:
        await context.bot.set_chat_title(chat.id, new_title)
    except Exception as e:
        logging.warning("Failed to set chat title: %s", e)
        try:
            await context.bot.send_message(
                chat.id,
                "⚠️ Не удалось переименовать группу. Проверьте права бота (управление группой).",
            )
        except Exception:
            pass

    await context.bot.send_message(
        chat.id,
        "✅ Клиент добавлен. Сделка создана.",
    )
    log_action("client_joined_project", new_user.id, "project", project["project_id"], None)


async def handle_new_chat_members(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        return

    project = get_project_by_group(chat.id)
    if not project:
        return

    for new_user in update.message.new_chat_members:
        await process_user_join(chat, project, new_user, context)


async def cmd_invite_dev(update: Update, context: ContextTypes.DEFAULT_TYPE):
    logging.info("INVITE_DEV by user=%s", update.effective_user.id)
