async def cmd_invite_links(update: Update, context: ContextTypes.DEFAULT_TYPE):
    logging.info("INVITE_LINKS by user=%s", update.effective_user.id)
    user = update.effective_user
    if not is_admin_user(user):
        await update.message.reply_text("❌ Недостаточно прав.")
        return
    dev_token = secrets.token_urlsafe(16)
    client_token = secrets.token_urlsafe(16)
    dev_expires = (now_local() + timedelta(days=7)).replace(microsecond=0).isoformat()
    client_expires = (now_local() + timedelta(days=30)).replace(microsecond=0).isoformat()
    create_invite(dev_token, ROLE_DEVELOPER, dev_expires)
    create_invite(client_token, ROLE_CLIENT, client_expires)
    dev_link = f"https://t.me/{BOT_USERNAME}?start=inv_{dev_token}"
    client_link = f"https://t.me/{BOT_USERNAME}?start=inv_{client_token}"
    await update.message.reply_text(
        "Ссылка для разработчика:\n"
        f"{dev_link}\n\n"
        "Ссылка для клиента:\n"
        f"{client_link}"
    )


def build_application():
    LOGGER.info("BOT application build started")
    app = Application.builder().token(TOKEN).build()

    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("proj", cmd_project))
    app.add_handler(CommandHandler("bind", cmd_bind))
    app.add_handler(CommandHandler("invite_dev", cmd_invite_dev))
    app.add_handler(CommandHandler("invite_client", cmd_invite_client))
    app.add_handler(CommandHandler("invite_links", cmd_invite_links))
    # /forward_summary можно вернуть позже, если нужен ручной отчет
    app.add_handler(MessageHandler(filters.FORWARDED, handle_forwarded))
    app.add_handler(MessageHandler(filters.ChatType.PRIVATE & filters.TEXT & ~filters.COMMAND, handle_private_message))
    app.add_handler(MessageHandler(filters.StatusUpdate.NEW_CHAT_MEMBERS, handle_new_chat_members))
    app.add_handler(ChatMemberHandler(on_chat_member, ChatMemberHandler.CHAT_MEMBER))
    LOGGER.info("BOT application build completed")
    return app
