def handler(event, context):
    try:
        method, path, body, err = _parse_event(event)
        LOGGER.info(
            "REQUEST method=%s path=%s rawPath=%s request_uri=%s",
            method,
            path,
            event.get("rawPath"),
            event.get("request_uri"),
        )

        if method == "OPTIONS":
            LOGGER.info("REQUEST preflight OPTIONS path=%s", path)
            return _empty_response(200)
        if err:
            LOGGER.warning("REQUEST bad payload parse_error=%s", err)
            return _json_response(400, {"ok": False, "error": err})

        if path.startswith("/bot"):
            if not TOKEN or TOKEN == "REPLACE_ME":
                LOGGER.error("BOT_TOKEN/TOKEN is not configured")
                return _json_response(500, {"ok": False, "error": "token_not_configured"})
            webhook_token = _extract_webhook_token(event, path)
            # API Gateway may pass template path "/bot/{token}" in `path`.
            if webhook_token and webhook_token not in {"{token}", "token"} and webhook_token != TOKEN:
                LOGGER.warning("Webhook token mismatch: got=%s", webhook_token)
                return _json_response(403, {"ok": False, "error": "forbidden"})
            if method != "POST":
                return _json_response(405, {"ok": False, "error": "method_not_allowed"})
            try:
                # Do not block webhook on DB/schema warm-up or bot processing.
                # Telegram only needs fast HTTP 200; processing continues in background.
                _dispatch_webhook_update_bg(body or {})
                LOGGER.info("WEBHOOK accepted for async processing")
                return _json_response(200, {"ok": True})
            except Exception as exc:
                LOGGER.exception("Webhook processing failed")
                # Avoid repeated Telegram retries on transient internal errors.
                return _json_response(200, {"ok": True, "accepted_with_error": str(exc)[:200]})

        if path.startswith("/api"):
            if method not in {"POST", "GET"}:
                return _json_response(405, {"ok": False, "error": "method_not_allowed"})
            try:
                _ensure_db_once()
                LOGGER.info("API processing started path=%s", path)
                return _handle_api(path, body or {})
            except Exception as exc:
                LOGGER.exception("API processing failed")
                return _json_response(
                    500,
                    {"ok": False, "error": "api_failed", "details": str(exc)[:300]},
                )

        if path in {"/", "/health"}:
            return _json_response(200, {"ok": True, "env": ENV})

        LOGGER.warning("REQUEST unknown path=%s", path)
        return _json_response(404, {"ok": False, "error": "not_found"})
    except Exception:
        LOGGER.exception("Unhandled handler error")
        try:
            p = ((event or {}).get("path") or (event or {}).get("rawPath") or "")
            if str(p).startswith("/bot"):
                # Never return 500 to Telegram webhook.
                return _json_response(200, {"ok": True, "accepted_with_error": "internal_error"})
        except Exception:
            pass
        return _json_response(500, {"ok": False, "error": "internal_error"})
